import React, { useState } from 'react';
import { useStyles } from '../styles'
import { Backdrop, CircularProgress, Input } from '@material-ui/core';
import axios from 'axios';

const Quotation = () => {
    const classes = useStyles()
    const [loading, setLoading] = useState(false)
    const [newF, setNew] = useState(null)
    const [old, setOld] = useState(null)
    const [priceList, setPriceList] = useState(null)

    const uploadOld = (event) => {
        setOld(event.target.files[0])
    }

    const uploadNew = (event) => {
        setNew(event.target.files[0])
    }

    const uploadPricelist = (event) => {
        setPriceList(event.target.files[0])
    }

    const ping = () => {
        axios.get('http://157.245.198.24:5000/health')
            .then(function (response) {
                // handle success
                console.log(response);
            })
            .catch(function (error) {
                // handle error
                console.log(error);
            })
            .then(function () {
                // always executed
            });

    }

    const handleClose = () => {
        setLoading(false);
    };

    const postRequest = async () => {
        if (old == null || newF == null || priceList == null) {
            alert('ensure all files have ben uploaded before proceeding')
            return
        }
        setLoading(true)
        const formData = new FormData();
        formData.append("old", old);
        formData.append("new", newF);
        formData.append("price_list", priceList);

        try {
            axios.post("https://157.245.198.24:5000/uploader", formData,
                {
                    headers:
                    {
                        'Content-Disposition': "attachment; filename=output.xlsx",
                        'Content-Type': 'multipart/form-data'
                    },
                    responseType: 'arraybuffer',
                }
            ).then(res => {
                console.log(res)
                const url = window.URL.createObjectURL(new Blob([res.data]));
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', 'output.xlsx');
                document.body.appendChild(link);
                link.click();
            }).catch(err => {
                console.log(err)
                alert(err)
            });
            setLoading(false)
        } catch (error) {
            console.log(error)
            setLoading(false)
        }

    }

    return (
        <div className={classes.root}>
            <span style={{ fontSize: '30px', marginBottom: '30px', textAlign: 'center', fontWeight: 'bold' }}>
                Quotation Compiler
            </span>
            <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Old File</span>
                    <Input onChange={(event) => uploadOld(event)} type="file" className={classes.fileUpload} />
                </div>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>New File</span>
                    <Input onChange={(event) => uploadNew(event)} type="file" className={classes.fileUpload} />
                </div>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Price List</span>
                    <Input onChange={(event) => uploadPricelist(event)} type="file" className={classes.fileUpload} />
                </div>
            </div>
            <div style={{ marginTop: '50px' }}>
                <button onClick={() => postRequest()} className={classes.download}>
                    Compile
                </button>
            </div>
            <Backdrop
                sx={{ color: '#fff', zIndex: (theme) => theme.zIndex.drawer + 1 }}
                open={loading}
            >
                <CircularProgress color="inherit" />
            </Backdrop>
        </div>
    );
}

export default Quotation;